1	import { z } from "zod";
2	import { PROVIDER_DISPLAY } from "../../client/display";
3	import { defineWebhookProvider } from "../../factory/index";
4	import { actionEvent, hmac } from "../../provider/index";
5	import type { CallbackResult, OAuthTokens } from "../../provider/primitives";
6	import { readErrorBody } from "../../runtime/http";
7	import {
8	  vercelApi,
9	  vercelProjectsListSchema,
10	  vercelTeamResponseSchema,
11	  vercelUserResponseSchema,
12	} from "./api";
13	import type { VercelAccountInfo, VercelConfig } from "./auth";
14	import {
15	  vercelAccountInfoSchema,
16	  vercelConfigSchema,
17	  vercelOAuthResponseSchema,
18	  vercelProviderConfigSchema,
19	} from "./auth";
20	import { vercelBackfill } from "./backfill";
21	import {
22	  preTransformVercelWebhookPayloadSchema,
23	  vercelWebhookPayloadSchema,
24	} from "./schemas";
25	import { transformVercelDeployment } from "./transformers";
26	
27	// ── Standalone OAuth helpers (avoids circular self-reference in processCallback) ──
28	
29	async function exchangeVercelCode(
30	  config: VercelConfig,
31	  code: string,
32	  redirectUri: string
33	): Promise<OAuthTokens> {
34	  const body = new URLSearchParams({
35	    client_id: config.clientSecretId,
36	    client_secret: config.clientIntegrationSecret,
37	    code,
38	    redirect_uri: redirectUri,
39	  });
40	
41	  const response = await fetch("https://api.vercel.com/v2/oauth/access_token", {
42	    method: "POST",
43	    headers: { "Content-Type": "application/x-www-form-urlencoded" },
44	    body: body.toString(),
45	    signal: AbortSignal.timeout(15_000),
46	  });
47	
48	  if (!response.ok) {
49	    const body = await readErrorBody(response);
50	    throw new Error(`Vercel token exchange failed: ${response.status} ${body}`);
51	  }
52	
53	  const rawData: unknown = await response.json();
54	  const data = vercelOAuthResponseSchema.parse(rawData);
55	
56	  return {
57	    accessToken: data.access_token,
58	    tokenType: data.token_type,
59	    raw: rawData as Record<string, unknown>,
60	  } satisfies OAuthTokens;
61	}
62	
63	// ── Provider Definition ──
64	
65	export const vercel = defineWebhookProvider({
66	  optional: true,
67	  envSchema: {
68	    VERCEL_INTEGRATION_SLUG: z.string().min(1).optional(),
69	    VERCEL_CLIENT_SECRET_ID: z.string().min(1).optional(),
70	    VERCEL_CLIENT_INTEGRATION_SECRET: z.string().min(1).optional(),
71	  },
72	  createConfig: (env, runtime): VercelConfig | null => {
73	    const integrationSlug = env.VERCEL_INTEGRATION_SLUG;
74	    const clientSecretId = env.VERCEL_CLIENT_SECRET_ID;
75	    const clientIntegrationSecret = env.VERCEL_CLIENT_INTEGRATION_SECRET;
76	    if (!(integrationSlug && clientSecretId && clientIntegrationSecret)) {
77	      return null;
78	    }
79	    return vercelConfigSchema.parse({
80	      integrationSlug,
81	      clientSecretId,
82	      clientIntegrationSecret,
83	      callbackBaseUrl: runtime.callbackBaseUrl,
84	    });
85	  },
86	  ...PROVIDER_DISPLAY.vercel,
87	  configSchema: vercelConfigSchema,
88	  accountInfoSchema: vercelAccountInfoSchema,
89	  providerConfigSchema: vercelProviderConfigSchema,
90	
91	  // Fine-grained categories for UI/PROVIDER_REGISTRY compatibility
92	  categories: {
93	    "deployment.created": {
94	      label: "Deployment Started",
95	      description: "Capture when new deployments begin",
96	      type: "observation",
97	    },
98	    "deployment.succeeded": {
99	      label: "Deployment Succeeded",
100	      description: "Capture successful deployment completions",
101	      type: "observation",
102	    },
103	    "deployment.ready": {
104	      label: "Deployment Ready",
105	      description: "Capture when deployments are live",
106	      type: "observation",
107	    },
108	    "deployment.error": {
109	      label: "Deployment Failed",
110	      description: "Capture deployment failures",
111	      type: "observation",
112	    },
113	    "deployment.canceled": {
114	      label: "Deployment Canceled",
115	      description: "Capture canceled deployments",
116	      type: "observation",
117	    },
118	    "deployment.check-rerequested": {
119	      label: "Check Re-requested",
120	      description: "Capture deployment check re-request events",
121	      type: "observation",
122	    },
123	  },
124	
125	  // Coarse-grained events for dispatch (resolveCategory strips dot-suffix)
126	  events: {
127	    deployment: actionEvent({
128	      label: "Deployment",
129	      weight: 40,
130	      schema: preTransformVercelWebhookPayloadSchema,
131	      transform: transformVercelDeployment,
132	      actions: {
133	        created: { label: "Deployment Started", weight: 30 },
134	        succeeded: { label: "Deployment Succeeded", weight: 40 },
135	        ready: { label: "Deployment Ready", weight: 40 },
136	        error: { label: "Deployment Failed", weight: 70 },
137	        canceled: { label: "Deployment Canceled", weight: 65 },
138	        "check-rerequested": {
139	          label: "Deployment Check Re-requested",
140	          weight: 25,
141	        },
142	      },
143	    }),
144	  },
145	
146	  defaultSyncEvents: [
147	    "deployment.created",
148	    "deployment.succeeded",
149	    "deployment.ready",
150	    "deployment.error",
151	    "deployment.canceled",
152	  ],
153	
154	  buildProviderConfig: ({ defaultSyncEvents }) => ({
155	    provider: "vercel" as const,
156	    type: "project" as const,
157	    sync: {
158	      events: [...defaultSyncEvents],
159	      autoSync: true,
160	    },
161	  }),
162	
163	  // Wire eventType "deployment.created" → dispatch category "deployment"
164	  resolveCategory: (eventType) => eventType.split(".")[0] ?? eventType,
165	
166	  getBaseEventType: (sourceType) => sourceType,
167	
168	  deriveObservationType: (sourceType) => sourceType.replace(".", "_"),
169	
170	  api: vercelApi,
171	  backfill: vercelBackfill,
172	
173	  healthCheck: {
174	    check: async (_config, _externalId, accessToken) => {
175	      if (!accessToken) {
176	        return "revoked";
177	      }
178	      const response = await fetch("https://api.vercel.com/v2/user", {
179	        method: "GET",
180	        signal: AbortSignal.timeout(10_000),
181	        headers: {
182	          Authorization: `Bearer ${accessToken}`,
183	        },
184	      });
185	      if (response.status === 200) {
186	        return "healthy";
187	      }
188	      if (response.status === 401 || response.status === 403) {
189	        return "revoked";
190	      }
191	      throw new Error(`Vercel health check failed: ${response.status}`);
192	    },
193	  },
194	
195	  resourcePicker: {
196	    installationMode: "multi",
197	    resourceLabel: "projects",
198	
199	    enrichInstallation: async (executeApi, inst) => {
200	      const info = inst.providerAccountInfo;
201	      try {
202	        if (info?.raw?.team_id) {
203	          const res = await executeApi({
204	            endpointId: "get-team",
205	            pathParams: { team_id: info.raw.team_id },
206	          });
207	          const data = vercelTeamResponseSchema.parse(res.data);
208	          return {
209	            id: inst.id,
210	            externalId: inst.externalId,
211	            label: data.slug ?? info.raw.team_id,
212	          };
213	        }
214	        const res = await executeApi({ endpointId: "get-user" });
215	        const data = vercelUserResponseSchema.parse(res.data);
216	        return {
217	          id: inst.id,
218	          externalId: inst.externalId,
219	          label: data.user?.username ?? inst.externalId,
220	        };
221	      } catch {
222	        const fallbackLabel =
